# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using System;
using UnityEngine;

[Serializable]
public class PlayerStats
{
    public int maxHealth = 100;
    public int currentHealth = 100;
    public int currency = 0;
    public int damage = 10;
}

public class PlayerGameManager : MonoBehaviour
{
    public PlayerStats playerStats = new PlayerStats();

    public event Action<int, int> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnDamageChanged;

    private void Start()
    {
        ClampStats();
        NotifyAll();
    }

    public void TakeDamage(int amount)
    {
        if (amount <= 0) return;

        playerStats.currentHealth -= amount;
        if (playerStats.currentHealth < 0)
            playerStats.currentHealth = 0;

        OnHealthChanged?.Invoke(playerStats.currentHealth, playerStats.maxHealth);
    }

    public void Heal(int amount)
    {
        if (amount <= 0) return;

        playerStats.currentHealth += amount;
        if (playerStats.currentHealth > playerStats.maxHealth)
            playerStats.currentHealth = playerStats.maxHealth;

        OnHealthChanged?.Invoke(playerStats.currentHealth, playerStats.maxHealth);
    }

    public void AddCurrency(int amount)
    {
        if (amount <= 0) return;

        playerStats.currency += amount;
        OnCurrencyChanged?.Invoke(playerStats.currency);
    }

    public bool SpendCurrency(int amount)
    {
        if (amount <= 0) return true;
        if (playerStats.currency < amount) return false;

        playerStats.currency -= amount;
        OnCurrencyChanged?.Invoke(playerStats.currency);
        return true;
    }

    public void IncreaseDamage(int amount)
    {
        if (amount <= 0) return;

        playerStats.damage += amount;
        OnDamageChanged?.Invoke(playerStats.damage);
    }

    public int CalculateDamage(int baseDamage, float multiplier)
    {
        int result = Mathf.Max(0, Mathf.RoundToInt(baseDamage * multiplier));
        return result;
    }

    public int CalculatePrice(int basePrice, float priceMultiplier, int quantity = 1)
    {
        if (quantity < 1) quantity = 1;
        int result = Mathf.Max(0, Mathf.RoundToInt(basePrice * priceMultiplier * quantity));
        return result;
    }

    public bool BuyHealth(int basePrice, float priceMultiplier, int healAmount)
    {
        int price = CalculatePrice(basePrice, priceMultiplier, 1);
        if (!SpendCurrency(price)) return false;

        Heal(healAmount);
        return true;
    }

    public bool BuyDamageUpgrade(int basePrice, float priceMultiplier, int damageIncrease)
    {
        int price = CalculatePrice(basePrice, priceMultiplier, 1);
        if (!SpendCurrency(price)) return false;

        IncreaseDamage(damageIncrease);
        return true;
    }

    public bool BuyCurrencyPack(int packAmount, int price)
    {
        if (packAmount <= 0 || price < 0) return false;
        if (!SpendCurrency(price)) return false;

        AddCurrency(packAmount);
        return true;
    }

    public void ApplyInAppPurchaseCurrency(int purchasedAmount)
    {
        if (purchasedAmount <= 0) return;
        AddCurrency(purchasedAmount);
    }

    private void ClampStats()
    {
        if (playerStats.maxHealth < 1) playerStats.maxHealth = 1;
        if (playerStats.currentHealth < 0) playerStats.currentHealth = 0;
        if (playerStats.currentHealth > playerStats.maxHealth) playerStats.currentHealth = playerStats.maxHealth;
        if (playerStats.currency < 0) playerStats.currency = 0;
        if (playerStats.damage < 0) playerStats.damage = 0;
    }

    private void NotifyAll()
    {
        OnHealthChanged?.Invoke(playerStats.currentHealth, playerStats.maxHealth);
        OnCurrencyChanged?.Invoke(playerStats.currency);
        OnDamageChanged?.Invoke(playerStats.damage);
    }
}

[Serializable]
public class ShopItem
{
    public string itemId;
    public int basePrice = 100;
    public float priceMultiplier = 1f;
    public int damageIncrease = 0;
    public int healAmount = 0;
    public int currencyPackAmount = 0;
    public int inAppPurchasePrice = 0;
}

public class ShopSystem : MonoBehaviour
{
    public PlayerGameManager playerGameManager;
    public ShopItem[] items;

    public bool PurchaseItem(string itemId)
    {
        if (playerGameManager == null || items == null) return false;

        for (int i = 0; i < items.Length; i++)
        {
            ShopItem item = items[i];
            if (item == null || item.itemId != itemId) continue;

            if (item.currencyPackAmount > 0)
            {
                return playerGameManager.BuyCurrencyPack(item.currencyPackAmount, item.inAppPurchasePrice);
            }

            if (item.damageIncrease > 0)
            {
                return playerGameManager.BuyDamageUpgrade(item.basePrice, item.priceMultiplier, item.damageIncrease);
            }

            if (item.healAmount > 0)
            {
                return playerGameManager.BuyHealth(item.basePrice, item.priceMultiplier, item.healAmount);
            }

            return false;
        }

        return false;
    }

    public int GetItemPrice(string itemId)
    {
        if (items == null) return 0;

        for (int i = 0; i < items.Length; i++)
        {
            ShopItem item = items[i];
            if (item == null || item.itemId != itemId) continue;

            if (item.currencyPackAmount > 0)
                return item.inAppPurchasePrice;

            return playerGameManager != null
                ? playerGameManager.CalculatePrice(item.basePrice, item.priceMultiplier, 1)
                : Mathf.Max(0, Mathf.RoundToInt(item.basePrice * item.priceMultiplier));
        }

        return 0;
    }
}